v1.name = TypeError();
TypeError && v1;
EOF | ./build/njs /testcase/variant_1 >/tmp/out1 2>&1 || true; echo exit=$?; sed -n '1,200p' /tmp/out1 || true

cat > /testcase/variant_2 << 'EOF'
// Variant 2: change the assigned name to a string (boundary for PROPERTY 3 key init)
// This variant checks whether name property set to a primitive avoids the crash.
const v1 = URIError();
// assign a primitive string rather than the constructor/function
v1.name = "URIError";
URIError && v1;
EOF | ./build/njs /testcase/variant_2 >/tmp/out2 2>&1 || true; echo exit=$?; sed -n '1,200p' /tmp/out2 || true

cat > /testcase/variant_3 << 'EOF'
