const v1 = ctor; // do not call ctor, put function itself in places
v1.name = ctor;
ctor && v1;
EOF | ./build/njs /testcase/variant_3 >/tmp/out3 2>&1 || true; echo exit=$?; sed -n '1,200p' /tmp/out3 || true

